    public void update(double value)
    {
        measurements++;
        sumsquares += value * value;
        sum += value;
        mean = sum / measurements;
        stdev = Math.sqrt((sumsquares / measurements) - (mean * mean));
        uncertainty = (stdev / Math.sqrt(measurements)) / mean;

        for (WaitForTargetUncertainty waiter : waiting)
        {
            if ((uncertainty < waiter.targetUncertainty && measurements >= waiter.minMeasurements) || (measurements >= waiter.maxMeasurements))
            {
                waiter.latch.countDown();
                // can safely remove as working over snapshot with COWArrayList
                waiting.remove(waiter);
            }
        }
    }

    public void update()
    {
        // we may race and add to the queue twice but no bad consequence so it's fine if that happens
        // as ultimately only the permits determine when to stop if wrap is true
        if (wrap && pendingRanges.isEmpty())
            pendingRanges.addAll(tokenRanges);
    }

    private static void update(LifecycleTransaction txn, Iterable<SSTableReader> readers, boolean originals)
    {
        for (SSTableReader reader : readers)
            txn.update(reader, originals);
    }

